async (params, browser) => {
  // Open StockX most popular
  await browser.open('https://stockx.com/sneakers/most-popular')

  // Wait for page
  await browser.waitForSelector('[data-testid=\'product-card\'], [class*=\'ProductCard\'], [class*=\'tile\']', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const items = []; document.querySelectorAll('[data-testid="product-card"], [class*="ProductCard"], [class*="tile"]').forEach((el, i) => { if (i < 20) { const nameEl = el.querySelector('p, [class*="name"], h3'); const priceEl = el.querySelector('[class*="price"], [class*="amount"]'); const imgEl = el.querySelector('img'); const linkEl = el.tagName === 'A' ? el : el.querySelector('a'); items.push({ name: nameEl?.textContent?.trim() || '', price: priceEl?.textContent?.trim() || '', image: imgEl?.src || '', url: linkEl?.href || '' }); } }); return { count: items.length, items };`)

  return result
}
